import javalang
import pandas as pd
import re

def try_parse(clean_code):
    """
    Attempts to wrap the code at different levels (Class, Method, or Statements)
    until javalang successfully builds the Abstract Syntax Tree (AST).
    """
    # 1. Tries to parse as is (in case it's already a complete class generated by the LLM)
    try:
        return javalang.parse.parse(clean_code)
    except Exception:
        pass

    # 2. Separates imports from the rest of the code.
    lines = clean_code.split('\n')
    imports = []
    body = []
    for line in lines:
        if line.strip().startswith("import ") or line.strip().startswith("package "):
            imports.append(line)
        else:
            body.append(line)
            
    str_imports = "\n".join(imports)
    str_body = "\n".join(body)

    # 3. ATTEMPT 2: Is the snippet a standalone method? 
    class_code = f"{str_imports}\npublic class DummyClass {{\n{str_body}\n}}"
    try:
        return javalang.parse.parse(class_code)
    except Exception:
        pass

    # 4. ATTEMPT 3: Is the snippet just standalone logic (Statements)?
    method_code = f"{str_imports}\npublic class DummyClass {{\n public void dummyMethod() throws Exception {{\n{str_body}\n}}\n}}"
    try:
        return javalang.parse.parse(method_code)
    except Exception:
        pass

    # 5. ATTEMPT 4 (Lifesaver): Did the LLM cut the code before closing braces?
    braces_code = method_code + "\n}\n}\n}"
    try:
        return javalang.parse.parse(braces_code)
    except Exception:
        return None # Give up, the syntax is truly broken

def extract_ast_paths(java_code):
    """
    Extracts syntactic signatures from the code, cleaning LLM artifacts.
    """
    code_str = str(java_code)
    
    # 1. Aggressive cleaning of LLM artifacts (Markdown, brackets, etc.)
    clean_code = code_str.replace("【", "").replace("】", "")
    clean_code = re.sub(r"^```java|```$", "", clean_code, flags=re.MULTILINE).strip()
    
    # 2. Searches for the syntax tree using progressive attempts
    tree = try_parse(clean_code)
    
    if tree is None:
        return "SYNTAX_ERROR"

    # 3. Feature extraction
    extracted_features = []
    for path, node in tree:
        if isinstance(node, javalang.tree.TryStatement):
            extracted_features.append("TryStatement")
            if node.resources and len(node.resources) > 0:
                extracted_features.append("HasResources_ImplicitClose")
            if getattr(node, 'finally_block', None):
                extracted_features.append("HasFinallyBlock")
                
        elif isinstance(node, javalang.tree.MethodInvocation):
            if node.member == "close":
                extracted_features.append("MethodCall_close")
            elif node.member == "disconnect":
                extracted_features.append("MethodCall_disconnect")
            elif node.member == "release":
                extracted_features.append("MethodCall_release")
            elif node.member == "recycle":
                extracted_features.append("MethodCall_recycle")
            elif node.member == "free":
                extracted_features.append("MethodCall_free")
            elif node.member == "destroy":
                extracted_features.append("MethodCall_destroy")
            else:
                extracted_features.append("MethodCall_Other")
                
        elif isinstance(node, javalang.tree.CatchClause):
            extracted_features.append("CatchClause")
            
    if not extracted_features:
        return "NO_RELEVANT_FEATURES"
        
    return " ".join(extracted_features)

def generate_ast_dataset_from_csv(input_csv_path, output_csv_path, id_column, code_column, label_column):
    print(f"📄 Reading snippets from file: {input_csv_path}")
    
    try:
        df = pd.read_csv(input_csv_path)
    except pd.errors.ParserError:
        try:
            df = pd.read_csv(input_csv_path, sep=';')
        except Exception:
            print("⚠️ Irregular format detected. Using Python parsing engine...")
            df = pd.read_csv(input_csv_path, sep=None, engine='python', on_bad_lines='skip')
    except UnicodeDecodeError:
        df = pd.read_csv(input_csv_path, encoding='latin1', sep=';')

    print(f"📊 Total records read from CSV: {len(df)}")
    
    if id_column not in df.columns or code_column not in df.columns or label_column not in df.columns:
        print(f"❌ CRITICAL ERROR: Columns '{id_column}', '{code_column}' or '{label_column}' not found!")
        print(f"Available columns in the file: {list(df.columns)}")
        return

    print("🌲 Extracting Abstract Syntax Trees (AST)... This may take a few seconds.")
    df['AST_Features'] = df[code_column].astype(str).apply(extract_ast_paths)
    
    errors = len(df[df['AST_Features'] == "SYNTAX_ERROR"])
    print(f"⚠️ Snippets ignored due to insurmountable syntax error: {errors}")
    
    # 1. Removes individual rows with errors
    df = df[df['AST_Features'] != "SYNTAX_ERROR"]
    
    # =====================================================================
    # 🛡️ NEW SHIELDING: REMOVAL OF ORPHAN PAIRS (Ensures 50% / 50%)
    # =====================================================================
    print("⚖️ Checking data parity (removing orphan cases)...")
    
    # Creates temporary pair ID column by removing the _BUG or _FIX suffix
    df['Pair_ID_Temp'] = df[id_column].apply(lambda x: str(x).rsplit('_', 1)[0])
    
    # Counts survivors. Perfect pairs should have exactly 2 occurrences
    pair_counts = df['Pair_ID_Temp'].value_counts()
    complete_pairs = pair_counts[pair_counts == 2].index
    
    # Filters, keeping only rows whose pairs are 100% complete
    df = df[df['Pair_ID_Temp'].isin(complete_pairs)]
    # =====================================================================

    # We filter to save, keeping the ID column intact
    final_df = df[[id_column, 'AST_Features', label_column]].copy()
    
    # Saves the complete new CSV
    final_df.to_csv(output_csv_path, index=False)
    
    # Metrics for your peace of mind in the console
    total_bugs = len(final_df[final_df[label_column] == 1])
    total_fix = len(final_df[final_df[label_column] == 0])
    
    print(f"\n✅ Extraction and Alignment completed successfully!")
    print(f"📊 Balanced structural dataset: {len(final_df)} valid rows.")
    print(f"   ↳ 🔴 Class 1 (With Bug): {total_bugs} examples")
    print(f"   ↳ 🟢 Class 0 (Fixed): {total_fix} examples")
    print(f"💾 File saved to: {output_csv_path}")

if __name__ == "__main__":
    INPUT_FILE = "C:/Dissertacao/data_bases/04_final/dataset_synthetic_chatgpt.csv" 
    OUTPUT_FILE = "C:/Dissertacao/data_bases/04_final/dataset_ast_complete.csv"
    
    ID_COLUMN = 'Case_ID'
    CODE_COLUMN = 'Code_Snippet' 
    LABEL_COLUMN = 'Has_Resource_Leak'
    
    generate_ast_dataset_from_csv(INPUT_FILE, OUTPUT_FILE, ID_COLUMN, CODE_COLUMN, LABEL_COLUMN)